    'e.g. Refresh access reviews for vCenter': "p. ex. Rafraîchir les revues d'accès vCenter",
    'e.g. Suspected data exfiltration via VPN': 'p. ex. Suspicion d\'exfiltration de données via VPN',
    'evd_a1b2c3d4 or run-20260508-1422': 'evd_a1b2c3d4 ou run-20260508-1422',
